    largest_smallest_integers([0]) == (None, None)
    '''
    neg_ints = [x for x in lst if x < 0]
    pos_ints = [x for x in lst if x > 0]

    if not neg_ints and not pos_ints:
        return (None, None)

    if not neg_ints:
        a = None
    else:
        a = max(neg_ints)

    if not pos_ints:
        b = None
    else:
        b = min(pos_ints)

    return (a, b)

